rss.channel:
{=site.title.escapeHtml.raw}
{=site.url.root.url.raw}
{=site.description.escapeHtml.raw}
{=now.rfc822.raw}
{#let posts_limit=cdi:siteConfig.feed.posts_limit.or(400)}
{#for post in site.collections.get('posts').orEmpty}{#if post_count <= posts_limit}


    {=post.title.escapeHtml.raw}

        {=post.url.prepend(site.url.root.url).raw}


        {=post.content.escapeHtml.raw}

    {=post.date.rfc822.raw}

        {=post.url.prepend(site.url.root.url).raw}

    {#let post_author=post.data.author.or(post.data.authors.get(0)).or(cdi:siteConfig.author)}
    {#let post_author=cdi:authors.get(post_author).or(post_author)}
    {#if post_author}
    {=post_author.name.or("").escapeHtml.raw}{#if post_author.twitter} (https://twitter.com/{=post_author.twitter.escapeHtml.raw}){/if}
    {/if}

{/let}{/let}{/if}{/for}
